"use client";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useSession, signOut } from "next-auth/react";
import { useState } from "react";
import {
    LayoutDashboard,
    Wallet,
    ArrowUpCircle,
    ArrowDownCircle,
    BarChart3,
    History,
    LogOut,
    Edit2 // Icon untuk edit
} from "lucide-react";
import { getLogo } from "@/lib/utils";

// Modal Komponen untuk Edit Profil (Dibuat di bawah)
import EditProfileModal from "/components/EditProfileModal";

export default function DashboardLayout({ children }: { children: React.ReactNode }) {
    const pathname = usePathname();
    const { data: session, update } = useSession(); // update() untuk refresh session setelah edit
    const [isEditModalOpen, setIsEditModalOpen] = useState(false);

    // Navigasi Item
    const menuItems = [
        { name: "Dashboard", href: "/dashboard", icon: LayoutDashboard },
        { name: "Manajemen Akun", href: "/dashboard/accounts", icon: Wallet },
        { name: "Pemasukan", href: "/dashboard/income", icon: ArrowUpCircle },
        { name: "Pengeluaran", href: "/dashboard/expense", icon: ArrowDownCircle },
        { name: "Analisis Pareto", href: "/dashboard/analytics", icon: BarChart3 },
        { name: "Recap Tahunan", href: "/dashboard/recap", icon: History },
    ];

    // Logika Logout (PENTING: Callback ke '/')
    const handleLogout = () => signOut({ callbackUrl: "/" });

    return (
        <div className="flex min-h-screen bg-slate-50">
            {/* SIDEBAR */}
            <aside className="w-72 bg-white border-r border-slate-100 flex flex-col fixed h-full z-40">
                {/* Logo ET-Pareto */}
                <div className="p-6 border-b border-slate-100 flex items-center gap-3">
                    <img src={getLogo("bca")} alt="" className="w-7 h-7" /> {/* Hiasan logo */}
                    <h1 className="text-xl font-bold text-blue-600">
                        ET-Pareto 📉
                    </h1>
                </div>

                {/* Navigasi Utama */}
                <nav className="flex-1 p-4 pt-8 space-y-2">
                    {menuItems.map((item) => {
                        const Icon = item.icon;
                        const isActive = pathname === item.href;
                        return (
                            <Link
                                key={item.name}
                                href={item.href}
                                className={`flex items-center gap-3.5 p-3.5 rounded-2xl text-sm font-semibold transition-all group ${
                                    isActive
                                        ? "bg-blue-600 text-white shadow-md shadow-blue-100" 
                                        : "text-slate-600 hover:bg-slate-100"
                                }`}
                            >
                                <Icon size={20} className={isActive ? "" : "text-slate-400 group-hover:text-blue-500"} />
                                {item.name}
                            </Link>
                        );
                    })}
                </nav>

                {/* BARU: BAGIAN PROFIL & LOGOUT DI KIRI BAWAH */}
                <div className="p-4 border-t border-slate-100 mt-auto bg-white/80 backdrop-blur-sm sticky bottom-0">
                    <div className="flex items-center justify-between p-3 rounded-2xl bg-slate-50 border border-slate-100">
                        
                        {/* Area Profil (Klik untuk Edit) */}
                        <div className="flex items-center gap-3 cursor-pointer group flex-1" onClick={() => setIsEditModalOpen(true)}>
                            {/* Foto Profil Dinamis */}
                            <div className="w-12 h-12 rounded-full overflow-hidden border-2 border-slate-200 relative group-hover:border-blue-300 transition-all">
                                <img 
                                    src={session?.user?.image || "/logos/avatar_default.svg"} // Sediakan default avatar
                                    alt={session?.user?.name || "User"}
                                    className="w-full h-full object-cover"
                                />
                                {/* Overlay Edit saat Hover */}
                                <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity rounded-full">
                                    <Edit2 className="text-white" size={16} />
                                </div>
                            </div>
                            
                            {/* Nama & Email */}
                            <div className="flex-1 min-w-0">
                                <p className="font-bold text-slate-800 text-sm truncate">
                                    {session?.user?.name || "Tamu"}
                                </p>
                                <p className="text-xs text-slate-400 truncate font-mono">
                                    {session?.user?.email?.split('@')[0]} {/* Tampilkan 'Fredheric' doang */}
                                </p>
                            </div>
                        </div>

                        {/* Tombol Logout (Pintu Terbuka Merah) */}
                        <button 
                            onClick={handleLogout}
                            className="p-3 rounded-full text-red-500 hover:bg-red-50 transition-all group shrink-0 ml-2"
                            title="Logout"
                        >
                            <LogOut size={22} className="group-hover:translate-x-1 transition-transform" />
                        </button>
                    </div>
                </div>
            </aside>

            {/* MAIN CONTENT Area (PENTING: ml-72) */}
            <main className="ml-72 flex-1 min-h-screen">
                {children}
            </main>

            {/* MODAL EDIT PROFIL */}
            <EditProfileModal
                isOpen={isEditModalOpen}
                onClose={() => setIsEditModalOpen(false)} 
                user={session?.user}
                onUpdate={update} // Oper fungsi update session
            />
        </div>
    );
}